import 'dart:async';

import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Parsed deep link data containing fractal configuration.
///
/// This class represents the configuration extracted from a deep link URL
/// like `fractalforge://view?type=mandelbrot&zoom=10&x=0.5`.
///
/// {@category Services}
class DeepLinkData {
  /// The fractal module ID (e.g., 'mandelbrot', 'julia', 'mandelbulb').
  final String type;

  /// Zoom level (magnification).
  final double? zoom;

  /// Pan X coordinate (2D fractals).
  final double? x;

  /// Pan Y coordinate (2D fractals).
  final double? y;

  /// Rotation X angle in radians (3D fractals).
  final double? rotX;

  /// Rotation Y angle in radians (3D fractals).
  final double? rotY;

  /// Rotation Z angle in radians (3D fractals).
  final double? rotZ;

  /// Number of iterations.
  final int? iterations;

  /// Bailout radius.
  final double? bailout;

  /// Color scheme index.
  final int? colorScheme;

  /// Power parameter (for fractals like Mandelbulb).
  final double? power;

  /// Julia set real constant (c.x).
  final double? juliaX;

  /// Julia set imaginary constant (c.y).
  final double? juliaY;

  const DeepLinkData({
    required this.type,
    this.zoom,
    this.x,
    this.y,
    this.rotX,
    this.rotY,
    this.rotZ,
    this.iterations,
    this.bailout,
    this.colorScheme,
    this.power,
    this.juliaX,
    this.juliaY,
  });

  /// Creates a [FractalViewState] from the parsed deep link data.
  FractalViewState toViewState() {
    return FractalViewState(
      pan: Vector2(x ?? 0.0, y ?? 0.0),
      zoom: zoom ?? 1.0,
      rotation: Vector3(rotX ?? 0.0, rotY ?? 0.0, rotZ ?? 0.0),
    );
  }

  /// Extracts fractal parameters from the deep link data.
  ///
  /// Returns a map of parameter IDs to values.
  Map<String, Object> toParams() {
    final params = <String, Object>{};

    if (iterations != null) params['iterations'] = iterations!;
    if (bailout != null) params['bailout'] = bailout!;
    if (colorScheme != null) params['colorScheme'] = colorScheme!;
    if (power != null) params['power'] = power!;
    if (juliaX != null) params['juliaX'] = juliaX!;
    if (juliaY != null) params['juliaY'] = juliaY!;

    return params;
  }

  @override
  String toString() {
    return 'DeepLinkData(type: $type, zoom: $zoom, x: $x, y: $y, '
        'rotX: $rotX, rotY: $rotY, rotZ: $rotZ, iterations: $iterations, '
        'bailout: $bailout, colorScheme: $colorScheme, power: $power, '
        'juliaX: $juliaX, juliaY: $juliaY)';
  }
}

/// Service for handling deep links with the `fractalforge://` scheme.
///
/// Supports URLs like:
/// - `fractalforge://view?type=mandelbrot&zoom=10&x=-0.5&y=0.1`
/// - `fractalforge://view?type=julia&juliaX=-0.7&juliaY=0.27&colorScheme=2`
/// - `fractalforge://view?type=mandelbulb&rotX=0.5&rotY=0.3&power=8`
///
/// {@category Services}
class DeepLinkService {
  static const String scheme = 'fractalforge';
  static const String host = 'view';

  // Method channel for receiving deep links from native code
  static const MethodChannel _channel = MethodChannel('com.fractalforge/deeplink');

  final StreamController<DeepLinkData> _linkController =
      StreamController<DeepLinkData>.broadcast();

  /// Stream of parsed deep link data.
  Stream<DeepLinkData> get linkStream => _linkController.stream;

  DeepLinkData? _initialLink;

  /// The initial deep link that launched the app (if any).
  DeepLinkData? get initialLink => _initialLink;

  /// Initializes the deep link service.
  ///
  /// Sets up listeners for incoming deep links from the platform.
  Future<void> initialize() async {
    // TEMPORARY SAFETY SWITCH (2026-02): deep link channel init causes a black screen
    // on some Samsung S24 devices during startup.
    // User confirmed deep links are not needed for the immediate release.
    // We leave parsing + stream support intact for later re-enable.
    const bool kEnableDeepLinks = bool.fromEnvironment('ENABLE_DEEP_LINKS', defaultValue: false);
    if (!kEnableDeepLinks) {
      return;
    }

    // Set up method channel handler for incoming links
    _channel.setMethodCallHandler(_handleMethodCall);

    // Try to get the initial link that launched the app
    try {
      final String? initialUri = await _channel.invokeMethod('getInitialLink');
      if (initialUri != null) {
        try {
          final uri = Uri.parse(initialUri);
          final data = parseUri(uri);
          if (data != null) {
            _initialLink = data;
          }
        } catch (e) {
          // Malformed URI, ignore
          if (kDebugMode) debugPrint('Failed to parse initial deep link URI: $e');
        }
      }
    } on PlatformException {
      // Platform doesn't support deep links or no initial link
    }
  }

  Future<dynamic> _handleMethodCall(MethodCall call) async {
    if (call.method == 'onDeepLink') {
      final String uriString = call.arguments as String;
      try {
        final uri = Uri.parse(uriString);
        final data = parseUri(uri);
        if (data != null) {
          _linkController.add(data);
        }
      } catch (e) {
        // Malformed URI, ignore
        if (kDebugMode) debugPrint('Failed to parse deep link URI: $e');
      }
    }
  }

  /// Parses a URI into [DeepLinkData].
  ///
  /// Returns null if the URI is not a valid fractalforge deep link or
  /// if the fractal type is not recognized.
  static DeepLinkData? parseUri(Uri uri, {List<String>? validFractalTypes}) {
    // Accept both 'fractalforge' scheme and https with our host
    if (uri.scheme != scheme && uri.scheme != 'https') {
      return null;
    }

    // For https, check the host matches exactly
    const allowedHosts = {'fractalforge.app', 'www.fractalforge.app'};
    if (uri.scheme == 'https' && !allowedHosts.contains(uri.host)) {
      return null;
    }

    // For custom scheme, accept 'view' as host or path
    final isViewPath = uri.host == host || uri.path == '/$host' || uri.path == host;
    if (uri.scheme == scheme && !isViewPath) {
      return null;
    }

    final params = uri.queryParameters;
    final type = params['type'];

    if (type == null || type.isEmpty) {
      return null;
    }

    // Reject type strings with unsafe characters (defense-in-depth)
    if (!RegExp(r'^[a-z0-9_]+$').hasMatch(type)) {
      return null;
    }

    // Validate fractal type if validation list provided
    if (validFractalTypes != null && !validFractalTypes.contains(type)) {
      return null;
    }

    return DeepLinkData(
      type: type,
      zoom: _parseBoundedDouble(params['zoom'], 0.001, 1e15, 'zoom'),
      x: _parseBoundedDouble(params['x'], -1e10, 1e10, 'x'),
      y: _parseBoundedDouble(params['y'], -1e10, 1e10, 'y'),
      rotX: _parseBoundedDouble(params['rotX'], -1e10, 1e10, 'rotX'),
      rotY: _parseBoundedDouble(params['rotY'], -1e10, 1e10, 'rotY'),
      rotZ: _parseBoundedDouble(params['rotZ'], -1e10, 1e10, 'rotZ'),
      iterations: _parseBoundedInt(params['iterations'], 1, 10000, 'iterations'),
      bailout: _parseBoundedDouble(params['bailout'], 1.0, 1e10, 'bailout'),
      colorScheme: _parseBoundedInt(params['colorScheme'], 0, 9999, 'colorScheme'),
      power: _parseBoundedDouble(params['power'], 1, 20, 'power'),
      juliaX: _parseBoundedDouble(params['juliaX'], -1e10, 1e10, 'juliaX'),
      juliaY: _parseBoundedDouble(params['juliaY'], -1e10, 1e10, 'juliaY'),
    );
  }

  /// Builds a shareable deep link URL from the current fractal state.
  ///
  /// The [moduleId] specifies the fractal type, [params] contains the
  /// fractal parameters, and [view] contains the camera/view state.
  static Uri buildUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final queryParams = <String, String>{
      'type': moduleId,
    };

    // Add view state
    if (view.zoom != 1.0) {
      queryParams['zoom'] = _formatDouble(view.zoom);
    }
    if (view.pan.x != 0.0) {
      queryParams['x'] = _formatDouble(view.pan.x);
    }
    if (view.pan.y != 0.0) {
      queryParams['y'] = _formatDouble(view.pan.y);
    }
    if (view.rotation.x != 0.0) {
      queryParams['rotX'] = _formatDouble(view.rotation.x);
    }
    if (view.rotation.y != 0.0) {
      queryParams['rotY'] = _formatDouble(view.rotation.y);
    }
    if (view.rotation.z != 0.0) {
      queryParams['rotZ'] = _formatDouble(view.rotation.z);
    }

    // Add fractal parameters
    if (params.containsKey('iterations')) {
      queryParams['iterations'] = params['iterations'].toString();
    }
    if (params.containsKey('bailout')) {
      queryParams['bailout'] = _formatDouble(_toDouble(params['bailout']));
    }
    if (params.containsKey('colorScheme')) {
      queryParams['colorScheme'] = params['colorScheme'].toString();
    }
    if (params.containsKey('power')) {
      queryParams['power'] = _formatDouble(_toDouble(params['power']));
    }
    if (params.containsKey('juliaX')) {
      queryParams['juliaX'] = _formatDouble(_toDouble(params['juliaX']));
    }
    if (params.containsKey('juliaY')) {
      queryParams['juliaY'] = _formatDouble(_toDouble(params['juliaY']));
    }

    return Uri(
      scheme: scheme,
      host: host,
      queryParameters: queryParams,
    );
  }

  /// Builds a web-compatible URL for sharing.
  ///
  /// Uses a hypothetical web domain for universal link support.
  static Uri buildWebUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final customUri = buildUri(moduleId: moduleId, params: params, view: view);
    return Uri(
      scheme: 'https',
      host: 'fractalforge.app',
      path: '/view',
      queryParameters: customUri.queryParameters,
    );
  }

  static double? _parseBoundedDouble(
      String? v, double min, double max, String paramName) {
    if (v == null) return null;
    final d = double.tryParse(v);
    if (d == null || d.isNaN || d.isInfinite) {
      if (kDebugMode) debugPrint(
          'DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = d.clamp(min, max);
    if (clamped != d) {
      if (kDebugMode) debugPrint(
          'DeepLink: "$paramName" value $d out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static int? _parseBoundedInt(
      String? v, int min, int max, String paramName) {
    if (v == null) return null;
    final i = int.tryParse(v);
    if (i == null) {
      if (kDebugMode) debugPrint(
          'DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = i.clamp(min, max);
    if (clamped != i) {
      if (kDebugMode) debugPrint(
          'DeepLink: "$paramName" value $i out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static String _formatDouble(double value) {
    // Remove trailing zeros for cleaner URLs
    final formatted = value.toStringAsFixed(6);
    return formatted.replaceAll(RegExp(r'\.?0+$'), '');
  }

  static double _toDouble(Object? value) {
    if (value is double) return value;
    if (value is int) return value.toDouble();
    if (value is String) return double.tryParse(value) ?? 0.0;
    return 0.0;
  }

  /// Disposes of the service and closes the stream.
  void dispose() {
    _linkController.close();
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/services/deep_link_service.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('DeepLinkService', () {
    group('parseUri', () {
      test('parses basic fractalforge:// URL', () {
        final uri = Uri.parse('fractalforge://view?type=mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
      });

      test('parses URL with zoom and pan parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=mandelbrot&zoom=10&x=-0.5&y=0.1');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 10.0);
        expect(data.x, -0.5);
        expect(data.y, 0.1);
      });

      test('parses URL with 3D rotation parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=mandelbulb&rotX=0.5&rotY=0.3&rotZ=0.1');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbulb');
        expect(data.rotX, 0.5);
        expect(data.rotY, 0.3);
        expect(data.rotZ, 0.1);
      });

      test('parses URL with fractal parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=julia&iterations=200&colorScheme=2&juliaX=-0.7&juliaY=0.27');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'julia');
        expect(data.iterations, 200);
        expect(data.colorScheme, 2);
        expect(data.juliaX, -0.7);
        expect(data.juliaY, 0.27);
      });

      test('returns null for non-fractalforge scheme', () {
        final uri = Uri.parse('https://example.com/view?type=mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('returns null for missing type parameter', () {
        final uri = Uri.parse('fractalforge://view?zoom=10');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('parses https://fractalforge.app universal link', () {
        final uri = Uri.parse(
            'https://fractalforge.app/view?type=mandelbrot&zoom=5');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 5.0);
      });
    });

    group('buildUri', () {
      test('builds basic URL with type only', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState.initial(),
        );

        expect(uri.scheme, 'fractalforge');
        expect(uri.host, 'view');
        expect(uri.queryParameters['type'], 'mandelbrot');
      });

      test('includes zoom when not default', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState(
            pan: Vector2.zero(),
            zoom: 5.0,
            rotation: Vector3.zero(),
          ),
        );

        expect(uri.queryParameters['zoom'], '5');
      });

      test('includes pan coordinates when not zero', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState(
            pan: Vector2(-0.5, 0.25),
            zoom: 1.0,
            rotation: Vector3.zero(),
          ),
        );

        expect(uri.queryParameters['x'], '-0.5');
        expect(uri.queryParameters['y'], '0.25');
      });

      test('includes rotation for 3D fractals', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbulb',
          params: {},
          view: FractalViewState(
            pan: Vector2.zero(),
            zoom: 1.0,
            rotation: Vector3(0.5, 0.3, 0.1),
          ),
        );

        expect(uri.queryParameters['rotX'], '0.5');
        expect(uri.queryParameters['rotY'], '0.3');
        expect(uri.queryParameters['rotZ'], '0.1');
      });

      test('includes fractal parameters', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {
            'iterations': 200,
            'colorScheme': 2,
            'bailout': 4.5,
          },
          view: FractalViewState.initial(),
        );

        expect(uri.queryParameters['iterations'], '200');
        expect(uri.queryParameters['colorScheme'], '2');
        expect(uri.queryParameters['bailout'], '4.5');
      });

      test('omits default values for cleaner URLs', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState.initial(),
        );

        // Default values should not be included
        expect(uri.queryParameters.containsKey('zoom'), isFalse);
        expect(uri.queryParameters.containsKey('x'), isFalse);
        expect(uri.queryParameters.containsKey('y'), isFalse);
        expect(uri.queryParameters.containsKey('rotX'), isFalse);
      });
    });

    group('DeepLinkData', () {
      test('toViewState creates correct FractalViewState', () {
        final data = DeepLinkData(
          type: 'mandelbrot',
          zoom: 5.0,
          x: -0.5,
          y: 0.25,
          rotX: 0.1,
          rotY: 0.2,
          rotZ: 0.3,
        );

        final viewState = data.toViewState();

        expect(viewState.zoom, closeTo(5.0, 0.001));
        expect(viewState.pan.x, closeTo(-0.5, 0.001));
        expect(viewState.pan.y, closeTo(0.25, 0.001));
        expect(viewState.rotation.x, closeTo(0.1, 0.001));
        expect(viewState.rotation.y, closeTo(0.2, 0.001));
        expect(viewState.rotation.z, closeTo(0.3, 0.001));
      });

      test('toViewState handles null values with defaults', () {
        final data = DeepLinkData(type: 'mandelbrot');

        final viewState = data.toViewState();

        expect(viewState.zoom, 1.0);
        expect(viewState.pan.x, 0.0);
        expect(viewState.pan.y, 0.0);
        expect(viewState.rotation.x, 0.0);
        expect(viewState.rotation.y, 0.0);
        expect(viewState.rotation.z, 0.0);
      });

      test('toParams extracts fractal parameters', () {
        final data = DeepLinkData(
          type: 'mandelbrot',
          iterations: 200,
          colorScheme: 2,
          bailout: 4.5,
          power: 8.0,
        );

        final params = data.toParams();

        expect(params['iterations'], 200);
        expect(params['colorScheme'], 2);
        expect(params['bailout'], 4.5);
        expect(params['power'], 8.0);
      });

      test('toParams omits null values', () {
        final data = DeepLinkData(
          type: 'mandelbrot',
          iterations: 200,
        );

        final params = data.toParams();

        expect(params.containsKey('iterations'), isTrue);
        expect(params.containsKey('colorScheme'), isFalse);
        expect(params.containsKey('bailout'), isFalse);
      });
    });

    group('buildWebUri', () {
      test('creates https URL with fractalforge.app host', () {
        final uri = DeepLinkService.buildWebUri(
          moduleId: 'mandelbrot',
          params: {'iterations': 100},
          view: FractalViewState.initial(),
        );

        expect(uri.scheme, 'https');
        expect(uri.host, 'fractalforge.app');
        expect(uri.path, '/view');
        expect(uri.queryParameters['type'], 'mandelbrot');
        expect(uri.queryParameters['iterations'], '100');
      });
    });

    group('round-trip', () {
      test('URL can be built and parsed back to same data', () {
        final originalView = FractalViewState(
          pan: Vector2(-0.747, 0.1),
          zoom: 25.0,
          rotation: Vector3.zero(),
        );
        final originalParams = {
          'iterations': 350,
          'colorScheme': 1,
          'bailout': 4.0,
        };

        // Build URL
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: originalParams,
          view: originalView,
        );

        // Parse it back
        final parsed = DeepLinkService.parseUri(uri);

        expect(parsed, isNotNull);
        expect(parsed!.type, 'mandelbrot');
        expect(parsed.zoom, 25.0);
        expect(parsed.x, closeTo(-0.747, 0.001));
        expect(parsed.y, closeTo(0.1, 0.001));
        expect(parsed.iterations, 350);
        expect(parsed.colorScheme, 1);
      });

      test('complete round-trip with all parameters preserves values', () {
        final originalView = FractalViewState(
          pan: Vector2(0.3, -0.15),
          zoom: 42.0,
          rotation: Vector3(0.5, 0.3, 0.1),
        );
        final originalParams = {
          'iterations': 500,
          'colorScheme': 3,
          'bailout': 8.0,
          'power': 8.0,
          'juliaX': -0.7,
          'juliaY': 0.27,
        };

        final uri = DeepLinkService.buildUri(
          moduleId: 'julia',
          params: originalParams,
          view: originalView,
        );

        final parsed = DeepLinkService.parseUri(uri);

        expect(parsed, isNotNull);
        expect(parsed!.type, 'julia');
        expect(parsed.zoom, closeTo(42.0, 0.001));
        expect(parsed.x, closeTo(0.3, 0.001));
        expect(parsed.y, closeTo(-0.15, 0.001));
        expect(parsed.rotX, closeTo(0.5, 0.001));
        expect(parsed.rotY, closeTo(0.3, 0.001));
        expect(parsed.rotZ, closeTo(0.1, 0.001));
        expect(parsed.iterations, 500);
        expect(parsed.colorScheme, 3);
        expect(parsed.bailout, closeTo(8.0, 0.001));
        expect(parsed.power, closeTo(8.0, 0.001));
        expect(parsed.juliaX, closeTo(-0.7, 0.001));
        expect(parsed.juliaY, closeTo(0.27, 0.001));
      });
    });

    group('parameter validation — bounds clamping', () {
      test('valid deep link with all parameters is parsed correctly', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbulb'
          '&zoom=50&x=-1.5&y=2.3'
          '&rotX=0.5&rotY=0.3&rotZ=0.1'
          '&iterations=500&bailout=6.0&colorScheme=3'
          '&power=8&juliaX=-0.7&juliaY=0.27',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbulb');
        expect(data.zoom, closeTo(50.0, 0.001));
        expect(data.x, closeTo(-1.5, 0.001));
        expect(data.y, closeTo(2.3, 0.001));
        expect(data.rotX, closeTo(0.5, 0.001));
        expect(data.rotY, closeTo(0.3, 0.001));
        expect(data.rotZ, closeTo(0.1, 0.001));
        expect(data.iterations, 500);
        expect(data.bailout, closeTo(6.0, 0.001));
        expect(data.colorScheme, 3);
        expect(data.power, closeTo(8.0, 0.001));
        expect(data.juliaX, closeTo(-0.7, 0.001));
        expect(data.juliaY, closeTo(0.27, 0.001));
      });

      test('missing optional parameters return null (not crash)', () {
        final uri = Uri.parse('fractalforge://view?type=mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, isNull);
        expect(data.x, isNull);
        expect(data.y, isNull);
        expect(data.rotX, isNull);
        expect(data.rotY, isNull);
        expect(data.rotZ, isNull);
        expect(data.iterations, isNull);
        expect(data.bailout, isNull);
        expect(data.colorScheme, isNull);
        expect(data.power, isNull);
        expect(data.juliaX, isNull);
        expect(data.juliaY, isNull);
      });

      test('malformed zoom value "abc" returns null for zoom', () {
        final uri = Uri.parse('fractalforge://view?type=mandelbrot&zoom=abc');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
